#include <iostream>
#include <vector>

using namespace std;

int find_nth_number(int n) {
    if (n < 0) {
        throw invalid_argument("n must be a non-negative integer");
    }
    if (n == 0 || n == 1) {
        return -1;
    } else if (n == 2) {
        return -1;
    } else {
        vector<int> sequence = {0, -1, -1};
        for (int i = 3; i <= n; ++i) {
            int next_number = sequence[i - 1] + sequence[i - 2] + sequence[i - 3];
            sequence.push_back(next_number);
        }
        return sequence[n];
    }
}

int main() {
    int n;
    cout << "Enter the value of n: ";
    cin >> n;

    try {
        cout << "The " << n << "th term of the sequence is: " << find_nth_number(n) << endl;
    } catch (const invalid_argument& e) {
        cout << e.what() << endl;
    }

    return 0;
}
